import os
import secrets
import time
from datetime import datetime, timedelta
from functools import wraps

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail, Message
from collections import defaultdict

app = Flask(__name__)

# Configuration
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')
app.config['SQLALCHEMY_DATABASE_URI'] = os.environ.get('DATABASE_URL', 'sqlite:///password_reset.db')
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

# Mail configuration
app.config['MAIL_SERVER'] = os.environ.get('MAIL_SERVER', 'smtp.gmail.com')
app.config['MAIL_PORT'] = int(os.environ.get('MAIL_PORT', 587))
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME', '')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD', '')
app.config['MAIL_DEFAULT_SENDER'] = os.environ.get('MAIL_DEFAULT_SENDER', 'noreply@example.com')

# App base URL for reset links
BASE_URL = os.environ.get('BASE_URL', 'http://localhost:5000')

# Rate limiting config
RATE_LIMIT_WINDOW = 3600  # 1 hour window
RATE_LIMIT_MAX_REQUESTS = 5  # max 5 requests per window per IP
RATE_LIMIT_MAX_PER_EMAIL = 3  # max 3 requests per window per email

db = SQLAlchemy(app)
mail = Mail(app)


# --- In-memory rate limiter ---
class RateLimiter:
    def __init__(self):
        self.ip_requests = defaultdict(list)
        self.email_requests = defaultdict(list)

    def _cleanup(self, request_list, window):
        """Remove expired entries."""
        cutoff = time.time() - window
        return [t for t in request_list if t > cutoff]

    def is_ip_rate_limited(self, ip):
        self.ip_requests[ip] = self._cleanup(self.ip_requests[ip], RATE_LIMIT_WINDOW)
        if len(self.ip_requests[ip]) >= RATE_LIMIT_MAX_REQUESTS:
            return True
        return False

    def is_email_rate_limited(self, email):
        self.email_requests[email] = self._cleanup(self.email_requests[email], RATE_LIMIT_WINDOW)
        if len(self.email_requests[email]) >= RATE_LIMIT_MAX_PER_EMAIL:
            return True
        return False

    def record_request(self, ip, email):
        now = time.time()
        self.ip_requests[ip].append(now)
        self.email_requests[email].append(now)


rate_limiter = RateLimiter()


def rate_limit_check(f):
    """Decorator to check rate limits before processing request."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ip = request.remote_addr or 'unknown'
        if rate_limiter.is_ip_rate_limited(ip):
            return jsonify({
                'error': 'Too many requests. Please try again later.',
                'retry_after_seconds': RATE_LIMIT_WINDOW
            }), 429
        return f(*args, **kwargs)
    return decorated_function


# --- Models ---
class User(db.Model):
    __tablename__ = 'users'

    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), unique=True, nullable=False, index=True)
    password_hash = db.Column(db.String(255), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    def __repr__(self):
        return f'<User {self.email}>'


class PasswordResetToken(db.Model):
    __tablename__ = 'password_reset_tokens'

    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), nullable=False, index=True)
    token = db.Column(db.String(128), unique=True, nullable=False, index=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, default=False)

    def is_expired(self):
        return datetime.utcnow() > self.expires_at

    def is_valid(self):
        return not self.used and not self.is_expired()

    def __repr__(self):
        return f'<PasswordResetToken {self.email}>'


# --- Helper functions ---
def generate_reset_token():
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(48)


def send_reset_email(email, token):
    """Send password reset email with the reset link."""
    reset_link = f"{BASE_URL}/reset-password?token={token}"

    msg = Message(
        subject='Password Reset Request',
        recipients=[email],
        html=f"""
        <h2>Password Reset Request</h2>
        <p>You requested a password reset. Click the link below to reset your password:</p>
        <p><a href="{reset_link}">{reset_link}</a></p>
        <p>This link will expire in 1 hour.</p>
        <p>If you did not request this reset, please ignore this email.</p>
        """,
        body=f"""
        Password Reset Request

        You requested a password reset. Use the link below to reset your password:

        {reset_link}

        This link will expire in 1 hour.

        If you did not request this reset, please ignore this email.
        """
    )

    try:
        mail.send(msg)
        return True
    except Exception as e:
        app.logger.error(f"Failed to send reset email to {email}: {e}")
        return False


def invalidate_existing_tokens(email):
    """Invalidate all existing unused tokens for this email."""
    PasswordResetToken.query.filter_by(
        email=email,
        used=False
    ).update({'used': True})
    db.session.commit()


# --- API Endpoints ---
@app.route('/api/password-reset/request', methods=['POST'])
@rate_limit_check
def request_password_reset():
    """
    Request a password reset link.
    Expects JSON: {"email": "user@example.com"}
    """
    data = request.get_json()

    if not data or 'email' not in data:
        return jsonify({'error': 'Email is required.'}), 400

    email = data['email'].strip().lower()

    if not email or '@' not in email:
        return jsonify({'error': 'Invalid email address.'}), 400

    # Check email-specific rate limit
    if rate_limiter.is_email_rate_limited(email):
        return jsonify({
            'error': 'Too many reset requests for this email. Please try again later.',
            'retry_after_seconds': RATE_LIMIT_WINDOW
        }), 429

    # Record the request for rate limiting (both IP and email)
    ip = request.remote_addr or 'unknown'
    rate_limiter.record_request(ip, email)

    # Always return success to prevent email enumeration attacks
    success_response = jsonify({
        'message': 'If an account with that email exists, a password reset link has been sent.'
    })

    # Check if user exists
    user = User.query.filter_by(email=email).first()
    if not user:
        # Return same response to prevent email enumeration
        return success_response, 200

    # Invalidate any existing tokens for this user
    invalidate_existing_tokens(email)

    # Generate new token
    token = generate_reset_token()
    expires_at = datetime.utcnow() + timedelta(hours=1)

    # Store token in database
    reset_token = PasswordResetToken(
        email=email,
        token=token,
        expires_at=expires_at
    )
    db.session.add(reset_token)
    db.session.commit()

    # Send email
    email_sent = send_reset_email(email, token)

    if not email_sent:
        app.logger.error(f"Failed to send password reset email to {email}")
        # Still return success to prevent enumeration

    return success_response, 200


@app.route('/api/password-reset/validate', methods=['POST'])
def validate_reset_token():
    """
    Validate a password reset token.
    Expects JSON: {"token": "..."}
    """
    data = request.get_json()

    if not data or 'token' not in data:
        return jsonify({'error': 'Token is required.'}), 400

    token = data['token'].strip()

    reset_token = PasswordResetToken.query.filter_by(token=token).first()

    if not reset_token or not reset_token.is_valid():
        return jsonify({'error': 'Invalid or expired token.'}), 400

    return jsonify({
        'message': 'Token is valid.',
        'email': reset_token.email
    }), 200


@app.route('/api/password-reset/reset', methods=['POST'])
def reset_password():
    """
    Reset password using a valid token.
    Expects JSON: {"token": "...", "new_password": "..."}
    """
    data = request.get_json()

    if not data or 'token' not in data or 'new_password' not in data:
        return jsonify({'error': 'Token and new_password are required.'}), 400

    token = data['token'].strip()
    new_password = data['new_password']

    # Basic password validation
    if len(new_password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters long.'}), 400

    # Find and validate token
    reset_token = PasswordResetToken.query.filter_by(token=token).first()

    if not reset_token or not reset_token.is_valid():
        return jsonify({'error': 'Invalid or expired token.'}), 400

    # Find user
    user = User.query.filter_by(email=reset_token.email).first()

    if not user:
        return jsonify({'error': 'User not found.'}), 404

    # Update password (in production, use werkzeug.security.generate_password_hash)
    from werkzeug.security import generate_password_hash
    user.password_hash = generate_password_hash(new_password)

    # Mark token as used
    reset_token.used = True

    db.session.commit()

    return jsonify({'message': 'Password has been reset successfully.'}), 200


